import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatQty, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, monthStartEnd, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { VatListingRow } from '../../../services/analytics/models';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const BangKeVatBanPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [rows, setRows] = useState<VatListingRow[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getVatSalesListing({ fromDate, toDate }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [fromDate,toDate,dispatch, reloadKey]);
  const refresh = () => setReloadKey(k => k + 1);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-percent" /> Bảng kê VAT bán ra</h1></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel('/accounting/vat-sales-listing/export-excel',{fromDate,toDate},`BangKeVatBanPage-${fromDate}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.filtersBar} data-testid={`erp-bang-ke-vat-ban-filters`}><DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v:DateRangeValue)=>{setFromDate(v.fromDate??'');setToDate(v.toDate??'');}} /><ListSearchRefreshButtons testIdPrefix="erp-bang-ke-vat-ban" onSearch={handleSearch} onRefresh={refresh} showSearch={false} /></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Số HĐ</th><th>Ngày</th><th>Đối tác</th><th>MST</th><th className={styles.colRight}>Tiền</th><th className={styles.colRight}>VAT</th><th className={styles.colRight}>Tổng</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i}><td>{r.invoiceNumber}</td><td>{formatDate(r.invoiceDate)}</td><td>{r.customerName??'—'}</td><td>{r.taxCode}</td><td className={styles.colRight}>{formatVnd(r.subTotal)}</td><td className={styles.colRight}>{formatVnd(r.vatAmount)}</td><td className={styles.colRight}>{formatVnd(r.totalAmount)}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default BangKeVatBanPage;
